import {
  SegmentGroup as SegmentGroupPrimitive,
  useSegmentGroup,
} from '@ark-ui/react/segment-group';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef, ReactElement, ReactNode } from 'react';
import { Children, cloneElement, forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './SegmentGroup.module.css';

const SegmentGroupRoot = forwardRef<
  ComponentRef<typeof SegmentGroupPrimitive.Root>,
  ComponentProps<typeof SegmentGroupPrimitive.Root>
>(function SegmentGroupRoot({ className, orientation = 'horizontal', ...props }, ref) {
  return (
    <SegmentGroupPrimitive.Root
      ref={ref}
      orientation={orientation}
      data-slot="segment-group-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const SegmentGroupRootProvider = forwardRef<
  ComponentRef<typeof SegmentGroupPrimitive.RootProvider>,
  ComponentProps<typeof SegmentGroupPrimitive.RootProvider>
>(function SegmentGroupRootProvider({ className, ...props }, ref) {
  return (
    <SegmentGroupPrimitive.RootProvider
      ref={ref}
      data-slot="segment-group-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const SegmentGroupLabel = forwardRef<
  ComponentRef<typeof SegmentGroupPrimitive.Label>,
  ComponentProps<typeof SegmentGroupPrimitive.Label>
>(function SegmentGroupLabel({ className, ...props }, ref) {
  return (
    <SegmentGroupPrimitive.Label
      ref={ref}
      data-slot="segment-group-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const SegmentGroupItem = forwardRef<
  ComponentRef<typeof SegmentGroupPrimitive.Item>,
  ComponentProps<typeof SegmentGroupPrimitive.Item>
>(function SegmentGroupItem({ asChild, children, className, ...props }, ref) {
  return (
    <SegmentGroupPrimitive.Item
      ref={ref}
      asChild={asChild}
      data-slot="segment-group-item"
      className={clsx(styles.item, normalizeClassName(className))}
      {...props}
    >
      {withItemHiddenInput(children, asChild)}
    </SegmentGroupPrimitive.Item>
  );
});

const SegmentGroupItemControl = forwardRef<
  ComponentRef<typeof SegmentGroupPrimitive.ItemControl>,
  ComponentProps<typeof SegmentGroupPrimitive.ItemControl>
>(function SegmentGroupItemControl({ className, ...props }, ref) {
  return (
    <SegmentGroupPrimitive.ItemControl
      ref={ref}
      data-slot="segment-group-item-control"
      className={clsx(styles.itemControl, normalizeClassName(className))}
      {...props}
    />
  );
});

const SegmentGroupItemText = forwardRef<
  ComponentRef<typeof SegmentGroupPrimitive.ItemText>,
  ComponentProps<typeof SegmentGroupPrimitive.ItemText>
>(function SegmentGroupItemText({ className, ...props }, ref) {
  return (
    <SegmentGroupPrimitive.ItemText
      ref={ref}
      data-slot="segment-group-item-text"
      className={clsx(styles.itemText, normalizeClassName(className))}
      {...props}
    />
  );
});

function withItemHiddenInput(children: ReactNode, asChild?: boolean) {
  const hiddenInput = (
    <SegmentGroupPrimitive.ItemHiddenInput data-slot="segment-group-item-hidden-input" />
  );

  if (!asChild) {
    return (
      <>
        {children}
        {hiddenInput}
      </>
    );
  }

  const child = Children.only(children) as ReactElement<{ children?: ReactNode }>;

  return cloneElement(child, {}, child.props.children, hiddenInput);
}

const SegmentGroupIndicator = forwardRef<
  ComponentRef<typeof SegmentGroupPrimitive.Indicator>,
  ComponentProps<typeof SegmentGroupPrimitive.Indicator>
>(function SegmentGroupIndicator({ className, ...props }, ref) {
  return (
    <SegmentGroupPrimitive.Indicator
      ref={ref}
      data-slot="segment-group-indicator"
      className={clsx(styles.indicator, normalizeClassName(className))}
      {...props}
    />
  );
});

function SegmentGroupItems({
  items,
}: {
  items: readonly { value: string; label: ReactNode; disabled?: boolean }[];
}) {
  return items.map(({ value, label, disabled }) => (
    <SegmentGroupItem key={value} value={value} disabled={disabled}>
      <SegmentGroupItemText>{label}</SegmentGroupItemText>
      <SegmentGroupItemControl />
    </SegmentGroupItem>
  ));
}

const SegmentGroup = Object.assign(SegmentGroupRoot, {
  Root: SegmentGroupRoot,
  RootProvider: SegmentGroupRootProvider,
  Label: SegmentGroupLabel,
  Item: SegmentGroupItem,
  ItemControl: SegmentGroupItemControl,
  ItemText: SegmentGroupItemText,
  Indicator: SegmentGroupIndicator,
  Items: SegmentGroupItems,
});

export { SegmentGroup, useSegmentGroup };

@layer moduix.components {
  .root {
    box-sizing: border-box;
    position: relative;
    isolation: isolate;
    display: inline-flex;
    max-width: var(--moduix-segment-group-max-width, 100%);
    align-items: stretch;
    gap: var(--moduix-segment-group-gap, var(--moduix-spacing-1));
    padding: var(--moduix-segment-group-padding, var(--moduix-spacing-1));
    border: var(--moduix-segment-group-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-segment-group-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-segment-group-radius, var(--moduix-radius-lg));
    background-color: var(--moduix-segment-group-bg, var(--moduix-color-muted));
    color: var(--moduix-segment-group-color, var(--moduix-color-foreground));

    &[data-orientation='vertical'] {
      flex-direction: column;
      align-items: stretch;
    }

    &[data-disabled] {
      opacity: var(--moduix-segment-group-disabled-opacity, var(--moduix-opacity-disabled));
    }

    &[data-invalid] {
      border-color: var(
        --moduix-segment-group-border-color-invalid,
        var(--moduix-color-destructive)
      );
    }
  }

  .label {
    position: relative;
    z-index: 1;
    color: var(
      --moduix-segment-group-label-color,
      var(--moduix-segment-group-color, var(--moduix-color-foreground))
    );
    font-size: var(--moduix-segment-group-label-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-segment-group-label-font-weight, var(--moduix-weight-semibold));
    line-height: var(--moduix-segment-group-label-line-height, var(--moduix-line-height-text-sm));
    user-select: none;
  }

  .item {
    box-sizing: border-box;
    position: relative;
    z-index: 1;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--moduix-segment-group-item-gap, var(--moduix-spacing-2));
    min-height: var(--moduix-segment-group-item-height, var(--moduix-size-sm));
    border-radius: var(--moduix-segment-group-item-radius, var(--moduix-radius-md));
    padding-inline: var(--moduix-segment-group-item-padding-x, var(--moduix-spacing-3-5));
    color: var(--moduix-segment-group-item-color, var(--moduix-color-muted-foreground));
    font-size: var(--moduix-segment-group-item-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-segment-group-item-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-segment-group-item-line-height, var(--moduix-line-height-text-sm));
    user-select: none;
    white-space: nowrap;
    cursor: pointer;
    outline: 0;
    transition:
      color var(--moduix-segment-group-transition, var(--moduix-transition-default)),
      opacity var(--moduix-segment-group-transition, var(--moduix-transition-default));

    @media (hover: hover) {
      &:hover:not([data-readonly], [data-disabled]) {
        color: var(--moduix-segment-group-item-color-hover, var(--moduix-color-foreground));
      }
    }

    &[data-state='checked'] {
      color: var(--moduix-segment-group-item-color-checked, var(--moduix-color-foreground));
    }

    &[data-focus-visible] {
      outline: var(
          --moduix-segment-group-focus-ring-width,
          var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
        )
        solid var(--moduix-segment-group-focus-ring-color, var(--moduix-color-ring));
      outline-offset: var(--moduix-segment-group-focus-ring-offset, var(--moduix-border-width-sm));
    }

    &[data-invalid][data-focus-visible] {
      outline-color: var(
        --moduix-segment-group-focus-ring-color-invalid,
        var(--moduix-color-destructive)
      );
    }

    &[data-readonly],
    &[data-disabled] {
      cursor: default;
    }

    &[data-disabled] {
      opacity: var(--moduix-segment-group-item-disabled-opacity, var(--moduix-opacity-disabled));
    }

    &[data-orientation='vertical'] {
      width: 100%;
      justify-content: flex-start;
    }
  }

  .itemControl {
    display: none;
  }

  .itemText {
    position: relative;
    z-index: 1;
  }

  .indicator {
    --transition-duration: var(
      --moduix-segment-group-indicator-transition-duration,
      var(--moduix-duration-normal)
    );
    --transition-timing-function: var(
      --moduix-segment-group-indicator-transition-timing-function,
      var(--moduix-ease-in-out)
    );

    position: absolute;
    z-index: 0;
    top: var(--top);
    left: var(--left);
    width: var(--width);
    height: var(--height);
    border-radius: var(--moduix-segment-group-indicator-radius, var(--moduix-radius-md));
    background-color: var(--moduix-segment-group-indicator-bg, var(--moduix-color-background));
    box-shadow: var(--moduix-segment-group-indicator-shadow, var(--moduix-shadow-sm));
    pointer-events: none;
  }
}
